import json
import logging
import hashlib
import hmac
import os
from datetime import datetime

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Secret for verifying webhook signatures (store in environment variable)
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', '')


def verify_webhook_signature(payload_body, signature_header):
    """Verify the webhook payload signature to ensure authenticity."""
    if not WEBHOOK_SECRET:
        logger.warning("No webhook secret configured - skipping signature verification")
        return True

    if not signature_header:
        return False

    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload_body.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(f"sha256={expected_signature}", signature_header)


def validate_event_payload(event_data):
    """Validate and sanitize the deserialized event payload."""
    required_fields = ['action', 'user_id', 'timestamp']

    for field in required_fields:
        if field not in event_data:
            raise ValueError(f"Missing required field: {field}")

    allowed_actions = [
        'user.created', 'user.updated', 'user.deleted',
        'order.placed', 'order.cancelled', 'order.completed',
        'payment.received', 'payment.failed'
    ]

    if event_data['action'] not in allowed_actions:
        raise ValueError(f"Unknown action: {event_data['action']}")

    # Validate user_id is a string/int, not something unexpected
    if not isinstance(event_data['user_id'], (str, int)):
        raise ValueError("Invalid user_id type")

    return event_data


def process_user_action(action_data):
    """Process the validated user action."""
    action = action_data['action']
    user_id = action_data['user_id']
    timestamp = action_data.get('timestamp', datetime.utcnow().isoformat())
    metadata = action_data.get('metadata', {})

    logger.info(f"Processing action '{action}' for user '{user_id}' at {timestamp}")

    # Route to appropriate handler based on action type
    action_handlers = {
        'user.created': handle_user_created,
        'user.updated': handle_user_updated,
        'user.deleted': handle_user_deleted,
        'order.placed': handle_order_placed,
        'order.cancelled': handle_order_cancelled,
        'order.completed': handle_order_completed,
        'payment.received': handle_payment_received,
        'payment.failed': handle_payment_failed,
    }

    handler = action_handlers.get(action)
    if handler:
        return handler(user_id, metadata, timestamp)
    else:
        raise ValueError(f"No handler for action: {action}")


def handle_user_created(user_id, metadata, timestamp):
    logger.info(f"User created: {user_id}")
    return {"status": "processed", "action": "user.created", "user_id": user_id}


