def lambda_handler(event, context):
    """
    AWS Lambda handler for processing webhook events from external partners.

    SECURITY NOTE: We use JSON (not pickle) for deserialization of external data.
    pickle.loads() on untrusted input is a Remote Code Execution vulnerability.
    Never use pickle to deserialize data from external/untrusted sources.
    """
    try:
        # Extract headers and body from API Gateway event
        headers = event.get('headers', {}) or {}
        body = event.get('body', '')

        if not body:
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'Empty request body'})
            }

        # Verify webhook signature
        signature = headers.get('x-webhook-signature', headers.get('X-Webhook-Signature', ''))
        if not verify_webhook_signature(body, signature):
            logger.warning("Invalid webhook signature received")
            return {
                'statusCode': 401,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'Invalid signature'})
            }

        # Safely deserialize using JSON (NEVER use pickle for external data)
        if event.get('isBase64Encoded', False):
            import base64
            body = base64.b64decode(body).decode('utf-8')

        try:
            event_data = json.loads(body)
        except json.JSONDecodeError as e:
            logger.error(f"Invalid JSON payload: {e}")
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({'error': 'Invalid JSON payload'})
            }

        # Handle batch events
        events_to_process = event_data if isinstance(event_data, list) else [event_data]
        results = []

        for single_event in events_to_process:
            try:
                validated_event = validate_event_payload(single_event)
                result = process_user_action(validated_event)
                results.append(result)
            except ValueError as e:
                logger.error(f"Validation error: {e}")
                results.append({"status": "error", "message": str(e)})

        response_body = {
            'message': 'Webhook processed successfully',
            'processed': len(results),
            'results': results
        }

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps(response_body)
        }

    except Exception as e:
        logger.error(f"Unexpected error processing webhook: {e}", exc_info=True)
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Internal server error'})
        }